import type { ExerciseVideoAttachment } from '../types/video'

const normalizeExerciseKey = (value: string) =>
  value
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/[^a-z0-9]+/g, ' ')
    .trim()

const normalizeBundledMediaUrl = (rawUrl: string): string =>
  rawUrl.startsWith('/media/') ? `https://wger.de${rawUrl}` : rawUrl

const createBundledAttachment = (
  rawUrl: string,
  licenseLabel: string,
  notes: string,
): ExerciseVideoAttachment => {
  const resolvedUrl = normalizeBundledMediaUrl(rawUrl)
  return {
    rawUrl: resolvedUrl,
    embedUrl: resolvedUrl,
    licenseLabel,
    notes,
    updatedAt: '2026-04-27T17:47:33.490Z',
  }
}

